class APMTransaction:
    """Represents a single transaction being monitored."""

    def __init__(self, name, transaction_type="custom"):
        self.name = name
        self.transaction_type = transaction_type
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.result = "success"
        self.spans = []
        self.context = {}
        self.stack_traces = []
        self.errors = []
        self.id = id(self)

    def end(self):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000

    def set_result(self, result):
        self.result = result

    def set_context(self, context):
        self.context.update(context)

    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "type": self.transaction_type,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "end_time": datetime.fromtimestamp(self.end_time).isoformat() if self.end_time else None,
            "duration_ms": self.duration_ms,
            "result": self.result,
            "context": self.context,
            "spans": [s.to_dict() for s in self.spans],
            "errors": self.errors,
        }


class APMSpan:
    """Represents a span within a transaction (e.g., DB query, HTTP call)."""

    def __init__(self, name, span_type="custom", subtype=None, action=None):
        self.name = name
        self.span_type = span_type
        self.subtype = subtype
        self.action = action
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.context = {}
        self.stack_trace = None
        self.id = id(self)

    def end(self):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000

    def set_context(self, context):
        self.context.update(context)

    def capture_stack_trace(self):
        import traceback
        self.stack_trace = traceback.format_stack()

    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "type": self.span_type,
            "subtype": self.subtype,
            "action": self.action,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "duration_ms": self.duration_ms,
            "context": self.context,
            "stack_trace": self.stack_trace,
        }


class CustomAPMClient:
    """Custom APM client that collects and stores performance data."""

    def __init__(self, config=None):
        self.config = config or {}
        self.service_name = self.config.get("SERVICE_NAME", "my-python-app")
        self.environment = self.config.get("ENVIRONMENT", "development")
        self.transactions = []
        self.current_transaction = None
        self.capture_body = self.config.get("CAPTURE_BODY", "all")
        self.capture_headers = self.config.get("CAPTURE_HEADERS", True)
        self.stack_trace_limit = self.config.get("STACK_TRACE_LIMIT", 50)
        self.transaction_max_spans = self.config.get("TRANSACTION_MAX_SPANS", 500)
        self.collect_db_queries = self.config.get("COLLECT_DB_QUERIES", True)

        # Storage for metrics
        self.metrics = {
            "total_transactions": 0,
            "total_errors": 0,
            "avg_response_time_ms": 0,
            "slow_transactions": [],
        }

        logger.info(
            f"Custom APM Client initialized for service '{self.service_name}' "
            f"in '{self.environment}' environment"
        )

    def begin_transaction(self, transaction_type="custom", name=None):
        transaction = APMTransaction(name=name or "unnamed", transaction_type=transaction_type)
        self.current_transaction = transaction
        logger.debug(f"Transaction started: {transaction.name}")
        return transaction

    def end_transaction(self, name=None, result="success"):
        if self.current_transaction:
            if name:
                self.current_transaction.name = name
            self.current_transaction.set_result(result)
            self.current_transaction.end()
            self.transactions.append(self.current_transaction)
            self._update_metrics(self.current_transaction)
            logger.info(
                f"Transaction ended: {self.current_transaction.name} "
                f"- Duration: {self.current_transaction.duration_ms:.2f}ms "
                f"- Result: {result}"
            )
            transaction = self.current_transaction
            self.current_transaction = None
            return transaction
        return None

    def begin_span(self, name, span_type="custom", subtype=None, action=None):
        span = APMSpan(name=name, span_type=span_type, subtype=subtype, action=action)
        if self.current_transaction:
            if len(self.current_transaction.spans) < self.transaction_max_spans:
                self.current_transaction.spans.append(span)
        span.capture_stack_trace()
        logger.debug(f"Span started: {name} (type: {span_type})")
        return span

    def end_span(self, span):
        if span:
            span.end()
            logger.debug(f"Span ended: {span.name} - Duration: {span.duration_ms:.2f}ms")

    def capture_exception(self, exc_info=None):
        import traceback
        import sys

        if exc_info is None:
            exc_info = sys.exc_info()

        error_data = {
            "timestamp": datetime.now().isoformat(),
            "exception": {
                "type": exc_info[0].__name__ if exc_info[0] else "Unknown",
                "message": str(exc_info[1]) if exc_info[1] else "Unknown error",
                "stacktrace": traceback.format_exception(*exc_info) if all(exc_info) else [],
            },
            "transaction": self.current_transaction.name if self.current_transaction else None,
        }

        if self.current_transaction:
            self.current_transaction.errors.append(error_data)

        self.metrics["total_errors"] += 1
        logger.error(f"Exception captured: {error_data['exception']['type']}: {error_data['exception']['message']}")
        return error_data

    def capture_message(self, message, level="info"):
        msg_data = {
            "timestamp": datetime.now().isoformat(),
            "message": message,
            "level": level,
            "transaction": self.current_transaction.name if self.current_transaction else None,
        }
        logger.log(getattr(logging, level.upper(), logging.INFO), f"APM Message: {message}")
        return msg_data

    def _update_metrics(self, transaction):
        self.metrics["total_transactions"] += 1
        total = self.metrics["total_transactions"]
        prev_avg = self.metrics["avg_response_time_ms"]
        self.metrics["avg_response_time_ms"] = (
            (prev_avg * (total - 1) + transaction.duration_ms) / total
        )

        # Track slow transactions (> 1000ms)
        slow_threshold = self.config.get("SLOW_TRANSACTION_THRESHOLD_MS", 1000)
        if transaction.duration_ms > slow_threshold:
            self.metrics["slow_transactions"].append({
                "name": transaction.name,
                "duration_ms": transaction.duration_ms,
                "timestamp": datetime.fromtimestamp(transaction.start_time).isoformat(),
            })

    def get_metrics_summary(self):
        return {
            "service_name": self.service_name,
            "environment": self.environment,
            "metrics": self.metrics,
            "recent_transactions": [
                t.to_dict() for t in self.transactions[-10:]
            ],
        }


