class InstrumentedDatabase:
    """SQLite database wrapper with APM instrumentation."""

    def __init__(self, db_path, apm_client):
        self.db_path = db_path
        self.apm_client = apm_client
        self.connection = None
        self._connect()
        self._initialize_schema()

    def _connect(self):
        self.connection = sqlite3.connect(self.db_path, check_same_thread=False)
        self.connection.row_factory = sqlite3.Row
        logger.info(f"Database connected: {self.db_path}")

    def _initialize_schema(self):
        """Create sample tables for demonstration."""
        queries = [
            """
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT NOT NULL UNIQUE,
                email TEXT NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
            """,
            """
            CREATE TABLE IF NOT EXISTS orders (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                product TEXT NOT NULL,
                amount REAL NOT NULL,
                status TEXT DEFAULT 'pending',
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(id)
            )
            """,
            """
            CREATE TABLE IF NOT EXISTS apm_events (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                event_type TEXT NOT NULL,
                event_data TEXT NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
            """,
        ]
        cursor = self.connection.cursor()
        for query in queries:
            cursor.execute(query)
        self.connection.commit()
        logger.info("Database schema initialized")

    def execute_query(self, query, params=None, fetch=True):
        """Execute a SQL query with APM span tracking."""
        # Determine query type
        query_type = query.strip().split()[0].upper()
        span_name = f"SQL {query_type}"

        span = self.apm_client.begin_span(
            name=span_name,
            span_type="db",
            subtype="sqlite",
            action=query_type.lower()
        )

        # Add query context
        span.set_context({
            "db": {
                "type": "sqlite",
                "statement": query,
                "params": str(params) if params else None,
                "instance": self.db_path,
            }
        })

        try:
            cursor = self.connection.cursor()
            if params:
                cursor.execute(query, params)
            else:
                cursor.execute(query)

            if fetch and query_type == "SELECT":
                results = cursor.fetchall()
                span.set_context({
                    "db": {
                        **span.context.get("db", {}),
                        "rows_affected": len(results),
                    }
                })
                self.apm_client.end_span(span)
                return [dict(row) for row in results]
            else:
                self.connection.commit()
                rows_affected = cursor.rowcount
                span.set_context({
                    "db": {
                        **span.context.get("db", {}),
                        "rows_affected": rows_affected,
                    }
                })
                self.apm_client.end_span(span)
                return cursor.lastrowid if query_type == "INSERT" else rows_affected

        except Exception as e:
            self.apm_client.capture_exception()
            self.apm_client.end_span(span)
            raise

    def store_apm_event(self, event_type, event_data):
        """Store APM event data in the database."""
        self.execute_query(
            "INSERT INTO apm_events (event_type, event_data) VALUES (?, ?)",
            (event_type, json.dumps(event_data)),
            fetch=False
        )

    def close(self):
        if self.connection:
            self.connection.close()
            logger.info("Database connection closed")


