def apm_trace(name=None, transaction_type="custom"):
    """Decorator to trace function execution with APM."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            trace_name = name or f"{func.__module__}.{func.__qualname__}"
            apm = get_apm_client()

            transaction = apm.begin_transaction(
                transaction_type=transaction_type,
                name=trace_name
            )

            try:
                result = func(*args, **kwargs)
                apm.end_transaction(name=trace_name, result="success")
                return result
            except Exception as e:
                apm.capture_exception()
                apm.end_transaction(name=trace_name, result="error")
                raise

        return wrapper
    return decorator


def apm_span(name=None, span_type="custom", subtype=None):
    """Decorator to create a span within the current transaction."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            span_name = name or f"{func.__module__}.{func.__qualname__}"
            apm = get_apm_client()

            span = apm.begin_span(
                name=span_name,
                span_type=span_type,
                subtype=subtype
            )

            try:
                result = func(*args, **kwargs)
                apm.end_span(span)
                return result
            except Exception as e:
                apm.capture_exception()
                apm.end_span(span)
                raise

        return wrapper
    return decorator


